Q2
```
int solve(const vector<int>& a) {
    const int n = (int)a.size();
    stack<pair<int,int>> stk;
    int mx = INT_MIN, ans = 0, depth = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] >= mx) {
            mx = a[i];
            depth = 0;
            stk.emplace(mx, 0);
            continue;
        }
        if (a[i] < a[i - 1]) {
            if (depth > 1)
                stk.emplace(a[i - 1], depth);
            depth = 1;
        } else {
            depth++;
            while (stk.top().first <= a[i]) {
                depth = max(depth, stk.top().second + 1);
                stk.pop();
            }
        }
        ans = max(ans, depth);
    }
    return ans;
}

int main() {
    cout << solve({5,3,4,4,7,11,8,5,11}) << endl; // 3
    cout << solve({1,2,3,4,5}) << endl; // 0
    cout << solve({5,4,3,2,1}) << endl; // 1
    cout << solve({10,8,4,9,7,2,7}) << endl; // 2
    cout << solve({9,4,4,7,2,3,4,8}) << endl; // 4
}
```
